import{_ as i,c as o,o as r,a5 as a,j as e}from"./chunks/framework.Dtwt352Q.js";const u=JSON.parse('{"title":"v1.1.16: Stability and Experience Optimization","description":"","frontmatter":{},"headers":[],"relativePath":"en/changelog/v1.1.16.md","filePath":"en/changelog/v1.1.16.md","lastUpdated":1772014034000}'),n={name:"en/changelog/v1.1.16.md"};function s(d,t,l,c,p,h){return r(),o("div",null,[...t[0]||(t[0]=[a('<h1 id="v1-1-16-stability-and-experience-optimization" tabindex="-1">v1.1.16: Stability and Experience Optimization <a class="header-anchor" href="#v1-1-16-stability-and-experience-optimization" aria-label="Permalink to “v1.1.16: Stability and Experience Optimization”">​</a></h1><p><strong>Release Date</strong>: January 13, 2026</p><hr><h2 id="one-line-summary" tabindex="-1">One-Line Summary <a class="header-anchor" href="#one-line-summary" aria-label="Permalink to “One-Line Summary”">​</a></h2><p>This update <strong>improves edit tool feedback mechanism</strong>, making it clearer whether code modifications succeeded, plus fixes multiple issues affecting daily use.</p><hr><h2 id="improvement-edit-tool-feedback-optimization" tabindex="-1">Improvement: Edit Tool Feedback Optimization <a class="header-anchor" href="#improvement-edit-tool-feedback-optimization" aria-label="Permalink to “Improvement: Edit Tool Feedback Optimization”">​</a></h2><h3 id="what-s-updated" tabindex="-1">What&#39;s Updated? <a class="header-anchor" href="#what-s-updated" aria-label="Permalink to “What&#39;s Updated?”">​</a></h3><p>Edit and write tools now provide clearer feedback, letting you know:</p><ul><li>Whether modifications were successfully applied</li><li>If failed, the specific reason</li></ul><p><strong>Before</strong>: Sometimes uncertain whether code changes actually took effect.</p><p><strong>Now</strong>: Each modification has clear success/failure indication.</p><hr><h2 id="improvement-environment-file-read-permission" tabindex="-1">Improvement: Environment File Read Permission <a class="header-anchor" href="#improvement-environment-file-read-permission" aria-label="Permalink to “Improvement: Environment File Read Permission”">​</a></h2><h3 id="what-s-updated-1" tabindex="-1">What&#39;s Updated? <a class="header-anchor" href="#what-s-updated-1" aria-label="Permalink to “What&#39;s Updated?”">​</a></h3><p>When reading <code>.env</code> and other environment configuration files, now <strong>asks user for permission</strong> instead of blocking directly.</p><p><strong>Before</strong>: Attempts to read environment files might be silently blocked.</p><p><strong>Now</strong>: OpenCode pops up permission confirmation, you can choose to allow or not.</p><p>This gives you more flexibility when needing help configuring environment variables, while maintaining security.</p><hr><h2 id="new-feature-cli-debug-tool-invocation" tabindex="-1">New Feature: CLI Debug Tool Invocation <a class="header-anchor" href="#new-feature-cli-debug-tool-invocation" aria-label="Permalink to “New Feature: CLI Debug Tool Invocation”">​</a></h2><h3 id="what-s-updated-2" tabindex="-1">What&#39;s Updated? <a class="header-anchor" href="#what-s-updated-2" aria-label="Permalink to “What&#39;s Updated?”">​</a></h3><p>You can now directly debug tool invocations from command line, convenient for development and testing.</p><h3 id="how-to-use" tabindex="-1">How to Use? <a class="header-anchor" href="#how-to-use" aria-label="Permalink to “How to Use?”">​</a></h3>',24),e("div",{class:"language-bash"},[e("button",{title:"Copy Code",class:"copy"}),e("span",{class:"lang"},"bash"),e("pre",null,[e("code",{"v-pre":""},"opencode debug tool <tool-name>")])],-1),a('<p>This is very helpful for developing custom tools or troubleshooting issues.</p><hr><h2 id="improvement-mcp-server-configuration" tabindex="-1">Improvement: MCP Server Configuration <a class="header-anchor" href="#improvement-mcp-server-configuration" aria-label="Permalink to “Improvement: MCP Server Configuration”">​</a></h2><h3 id="fix-mcp-add-command" tabindex="-1">Fix: <code>mcp add</code> Command <a class="header-anchor" href="#fix-mcp-add-command" aria-label="Permalink to “Fix: mcp add Command”">​</a></h3><p><strong>Previous Issue</strong>: When using <code>mcp add</code> to add MCP server, configuration wasn&#39;t actually written to OpenCode configuration file.</p><p><strong>Now</strong>: Configuration saves correctly, added MCP servers are automatically available on next startup.</p><hr><h2 id="improvement-subagent-permissions" tabindex="-1">Improvement: Subagent Permissions <a class="header-anchor" href="#improvement-subagent-permissions" aria-label="Permalink to “Improvement: Subagent Permissions”">​</a></h2><h3 id="what-s-updated-3" tabindex="-1">What&#39;s Updated? <a class="header-anchor" href="#what-s-updated-3" aria-label="Permalink to “What&#39;s Updated?”">​</a></h3><p>Nested subagents now correctly inherit parent agent&#39;s task permission settings.</p><p><strong>Before</strong>: Sometimes subagent permission settings didn&#39;t take effect.</p><p><strong>Now</strong>: Permission settings are correctly passed throughout the agent call chain.</p><hr><h2 id="desktop-app-updates" tabindex="-1">Desktop App Updates <a class="header-anchor" href="#desktop-app-updates" aria-label="Permalink to “Desktop App Updates”">​</a></h2><ul><li><strong>Local server password</strong>: Desktop app started local server now supports password protection</li><li><strong>Terminal numbering optimization</strong>: Smarter numbering in multi-terminal scenarios</li><li><strong>Windows fix</strong>: Fix Windows Tauri CLI startup parameter issue</li></ul><hr><h2 id="other-fixes" tabindex="-1">Other Fixes <a class="header-anchor" href="#other-fixes" aria-label="Permalink to “Other Fixes”">​</a></h2><table tabindex="0"><thead><tr><th>Issue</th><th>Fix</th></tr></thead><tbody><tr><td>Accidental submit when switching sessions</td><td>✅ Fixed</td></tr><tr><td>Console showing <code>[object Object]</code> error</td><td>✅ Fixed</td></tr><tr><td>Cloudflare provider token limit error</td><td>✅ Fixed</td></tr><tr><td>Bedrock Anthropic model inference configuration</td><td>✅ Fixed</td></tr></tbody></table><hr><h2 id="should-you-upgrade" tabindex="-1">Should You Upgrade? <a class="header-anchor" href="#should-you-upgrade" aria-label="Permalink to “Should You Upgrade?”">​</a></h2><table tabindex="0"><thead><tr><th>Situation</th><th>Recommendation</th></tr></thead><tbody><tr><td>Used <code>mcp add</code> but server didn&#39;t take effect</td><td>✅ Upgrade</td></tr><tr><td>Using Cloudflare provider</td><td>✅ Upgrade</td></tr><tr><td>Using AWS Bedrock + Claude</td><td>✅ Upgrade</td></tr><tr><td>Encountered uncertainty after editing</td><td>✅ Upgrade</td></tr><tr><td>Everything works fine</td><td>Can wait for next time</td></tr></tbody></table><p><strong>Upgrade Command</strong>:</p>',22),e("div",{class:"language-bash"},[e("button",{title:"Copy Code",class:"copy"}),e("span",{class:"lang"},"bash"),e("pre",null,[e("code",{"v-pre":""},"opencode upgrade")])],-1),a('<hr><h2 id="technical-details-skippable" tabindex="-1">Technical Details (Skippable) <a class="header-anchor" href="#technical-details-skippable" aria-label="Permalink to “Technical Details (Skippable)”">​</a></h2><details><summary>Click to expand full changelog</summary><h3 id="core" tabindex="-1">Core <a class="header-anchor" href="#core" aria-label="Permalink to “Core”">​</a></h3><ul><li>Handle write error when updating OpenCode configuration schema (@ShoeBoom)</li><li>Ensure zai models disable clear_thinking</li><li>Improve edit and write tool feedback, avoid confusion about modification results</li><li>Prevent console output [object Object] error (@lengmodkx)</li><li>Nested subagents correctly inherit parent agent task permissions (@malhashemi)</li><li>Fix Cloudflare provider max completion tokens error (@roerohan)</li><li>Bedrock Anthropic models use reasoningConfig (@Adam8234)</li><li>Store API URL in session metadata (@jkoelker)</li><li>Add nova-2 to region prefix models</li><li>Environment file read changed to ask user permission</li><li>Use Biome check instead of format to include import sorting (@kynnyhsap)</li></ul><h3 id="tui" tabindex="-1">TUI <a class="header-anchor" href="#tui" aria-label="Permalink to “TUI”">​</a></h3><ul><li>CLI supports directly debugging tool invocation (@Eric-Guo)</li><li>No longer submit prompt when switching sessions (@LeonMueller-OneAndOnly)</li><li>Await auth.set when setting API key to prevent race condition (@darshkpatel)</li><li><code>mcp add</code> command now correctly modifies OpenCode configuration (@paoloricciuti)</li></ul><h3 id="desktop" tabindex="-1">Desktop <a class="header-anchor" href="#desktop" aria-label="Permalink to “Desktop”">​</a></h3><ul><li>Desktop app starts local server with password (@Brendonovich)</li><li>Fix Windows Tauri CLI startup missing parameter (@pschiel)</li><li>Implement better dynamic terminal numbering (@OpeOginni)</li><li>Add delete button to server selection dialog (@OpeOginni)</li></ul><h3 id="community-contributors-15-contributors" tabindex="-1">Community Contributors (15 contributors) <a class="header-anchor" href="#community-contributors-15-contributors" aria-label="Permalink to “Community Contributors (15 contributors)”">​</a></h3><p>@kynnyhsap, @OpeOginni, @jkoelker, @paoloricciuti, @jerome-benoit, @darshkpatel, @Adam8234, @roerohan, @malhashemi, @pschiel, @lengmodkx, @LeonMueller-OneAndOnly, @Eric-Guo, @ShoeBoom, @Brendonovich</p></details><hr><p><a href="./">← Back to Changelog</a></p>',5)])])}const g=i(n,[["render",s]]);export{u as __pageData,g as default};
